  1→import React, { useRef, useEffect, useCallback, useMemo } from 'react';
  2→import { Layer, Shape, Text } from 'react-konva';
  3→import { STAR_COLORS } from '../utils/starUtils';
  4→
  5→const parseHex = (hex) => ({
  6→    r: parseInt(hex.slice(1, 3), 16),
  7→    g: parseInt(hex.slice(3, 5), 16),
  8→    b: parseInt(hex.slice(5, 7), 16),
  9→});
 10→
 11→const ConstellationLayer = React.memo(({ layerProps, constellations, computedStarPositions, zoom, chainColors, userId }) => {
 12→    const shapeRef = useRef(null);
 13→    const animRef = useRef({ time: 0, raf: null });
 14→
 15→    const linkData = useMemo(() => {
 16→        if (!Array.isArray(constellations) || constellations.length === 0) return [];
 17→        return constellations.map((link, i) => {
 18→            const colorHex = chainColors?.get(link.id) || STAR_COLORS[i % STAR_COLORS.length];
 19→            const rgb = parseHex(colorHex);
 20→            const isPending = link.status === 'pending';
 21→            const isDeclined = link.status === 'declined';
 22→            const isOwnPending = isPending && (link.user_id_a === userId || link.user_id_b === userId);
 23→            return { ...link, rgb, colorHex, isPending, isDeclined, isOwnPending };
 24→        });
 25→    }, [constellations, chainColors, userId]);
 26→
 27→    // Resolve positions for each link
 28→    const resolvedLinks = useMemo(() => {
 29→        return linkData
 30→            .filter(link => !link.isDeclined)
 31→            .filter(link => !link.isPending || link.isOwnPending)
 32→            .map(link => {
 33→                const posA = computedStarPositions.get(link.star_id_a)
 34→                    || (link.a_universe_x != null ? { x: link.a_universe_x, y: link.a_universe_y } : null);
 35→                const posB = computedStarPositions.get(link.star_id_b)
 36→                    || (link.b_universe_x != null ? { x: link.b_universe_x, y: link.b_universe_y } : null);
 37→                if (!posA || !posB) return null;
 38→                return { ...link, ax: posA.x, ay: posA.y, bx: posB.x, by: posB.y };
 39→            })
 40→            .filter(Boolean);
 41→    }, [linkData, computedStarPositions]);
 42→
 43→    const animate = useCallback(() => {
 44→        animRef.current.time = performance.now();
 45→        const node = shapeRef.current;
 46→        if (node) {
 47→            const layer = node.getLayer();
 48→            if (layer) layer.batchDraw();
 49→        }
 50→        animRef.current.raf = requestAnimationFrame(animate);
 51→    }, []);
 52→
 53→    useEffect(() => {
 54→        const hasAccepted = resolvedLinks.some(l => !l.isPending);
 55→        if (!hasAccepted) return;
 56→        animRef.current.raf = requestAnimationFrame(animate);
 57→        return () => {
 58→            if (animRef.current.raf) cancelAnimationFrame(animRef.current.raf);
 59→        };
 60→    }, [animate, resolvedLinks]);
 61→
 62→    if (resolvedLinks.length === 0) return null;
 63→
 64→    // Separate labels for Konva Text nodes (need scaleX/scaleY zoom correction)
 65→    const labels = resolvedLinks.filter(l => !l.isPending && l.label);
 66→
 67→    return (
 68→        <Layer {...layerProps} listening={false}>
 69→            <Shape
 70→                ref={shapeRef}
 71→                sceneFunc={(ctx) => {
 72→                    const time = animRef.current.time || performance.now();
 73→
 74→                    for (const link of resolvedLinks) {
 75→                        const { ax, ay, bx, by, rgb } = link;
 76→
 77→                        if (link.isPending) {
 78→                            // Pending: simple faint dashed line
 79→                            ctx.save();
 80→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.08)`;
 81→                            ctx.lineWidth = 1;
 82→                            ctx.setLineDash([5, 10]);
 83→                            ctx.lineCap = 'round';
 84→                            ctx.beginPath();
 85→                            ctx.moveTo(ax, ay);
 86→                            ctx.lineTo(bx, by);
 87→                            ctx.stroke();
 88→                            ctx.restore();
 89→                            continue;
 90→                        }
 91→
 92→                        // Accepted: triple-layer glow
 93→
 94→                        // Layer 1: Wide underglow
 95→                        ctx.save();
 96→                        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.06)`;
 97→                        ctx.lineWidth = 8;
 98→                        ctx.lineCap = 'round';
 99→                        ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.3)`;
100→                        ctx.shadowBlur = 20;
101→                        ctx.setLineDash([]);
102→                        ctx.beginPath();
103→                        ctx.moveTo(ax, ay);
104→                        ctx.lineTo(bx, by);
105→                        ctx.stroke();
106→                        ctx.restore();
107→
108→                        // Layer 2: Medium body
109→                        ctx.save();
110→                        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.12)`;
111→                        ctx.lineWidth = 3;
112→                        ctx.lineCap = 'round';
113→                        ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.3)`;
114→                        ctx.shadowBlur = 8;
115→                        ctx.setLineDash([]);
116→                        ctx.beginPath();
117→                        ctx.moveTo(ax, ay);
118→                        ctx.lineTo(bx, by);
119→                        ctx.stroke();
120→                        ctx.restore();
121→
122→                        // Layer 3: Thin animated core
123→                        ctx.save();
124→                        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.45)`;
125→                        ctx.lineWidth = 1.2;
126→                        ctx.lineCap = 'round';
127→                        ctx.setLineDash([14, 10]);
128→                        ctx.lineDashOffset = time * 0.04;
129→                        ctx.beginPath();
130→                        ctx.moveTo(ax, ay);
131→                        ctx.lineTo(bx, by);
132→                        ctx.stroke();
133→                        ctx.restore();
134→                    }
135→                }}
136→                perfectDrawEnabled={false}
137→                listening={false}
138→            />
139→            {/* Labels rendered as Konva Text for zoom correction */}
140→            {labels.map((link) => {
141→                const mx = (link.ax + link.bx) / 2;
142→                const my = (link.ay + link.by) / 2;
143→                return (
144→                    <Text
145→                        key={`label-${link.id}`}
146→                        x={mx}
147→                        y={my - 14}
148→                        text={link.label}
149→                        fontSize={12}
150→                        fontFamily="sans-serif"
151→                        fill={`rgba(${link.rgb.r},${link.rgb.g},${link.rgb.b},0.7)`}
152→                        align="center"
153→                        offsetX={link.label.length * 3}
154→                        scaleX={1 / zoom}
155→                        scaleY={1 / zoom}
156→                        listening={false}
157→                        perfectDrawEnabled={false}
158→                    />
159→                );
160→            })}
161→        </Layer>
162→    );
163→});
164→
165→ConstellationLayer.displayName = 'ConstellationLayer';
166→
167→export default ConstellationLayer;
