  1→import React, { useRef, useEffect } from 'react';
  2→import { Group, Circle, Text } from 'react-konva';
  3→import Konva from 'konva';
  4→import { hexToRgba } from '../utils/starUtils';
  5→
  6→const StarGroup = React.memo(({ x, y, radius, color, title, showTitle, isPulsing, onClick, onPointerDown, constellationColor }) => {
  7→    const r = radius;
  8→    const groupRef = useRef(null);
  9→    const tweenRef = useRef(null);
 10→
 11→    useEffect(() => {
 12→        const node = groupRef.current;
 13→        if (!node) return;
 14→
 15→        // Cleanup any running tween
 16→        if (tweenRef.current) {
 17→            tweenRef.current.destroy();
 18→            tweenRef.current = null;
 19→        }
 20→
 21→        if (isPulsing) {
 22→            // Phase 1: elastic scale up 1 → 1.8
 23→            const tweenUp = new Konva.Tween({
 24→                node,
 25→                scaleX: 1.8,
 26→                scaleY: 1.8,
 27→                duration: 0.35,
 28→                easing: Konva.Easings.ElasticEaseOut,
 29→                onFinish: () => {
 30→                    // Phase 2: ease back down 1.8 → 1
 31→                    const tweenDown = new Konva.Tween({
 32→                        node,
 33→                        scaleX: 1,
 34→                        scaleY: 1,
 35→                        duration: 0.25,
 36→                        easing: Konva.Easings.EaseOut,
 37→                    });
 38→                    tweenRef.current = tweenDown;
 39→                    tweenDown.play();
 40→                },
 41→            });
 42→            tweenRef.current = tweenUp;
 43→            tweenUp.play();
 44→        } else {
 45→            // Reset to default scale
 46→            node.scaleX(1);
 47→            node.scaleY(1);
 48→        }
 49→
 50→        return () => {
 51→            if (tweenRef.current) {
 52→                tweenRef.current.destroy();
 53→                tweenRef.current = null;
 54→            }
 55→        };
 56→    }, [isPulsing]);
 57→
 58→    return (
 59→        <Group
 60→            ref={groupRef}
 61→            x={x}
 62→            y={y}
 63→        >
 64→            {/* Outer atmosphere — shadow glow */}
 65→            <Circle
 66→                radius={r * 3}
 67→                fill="transparent"
 68→                shadowColor={color}
 69→                shadowBlur={r * 5}
 70→                shadowOpacity={1}
 71→                perfectDrawEnabled={false}
 72→                shadowForStrokeEnabled={false}
 73→                listening={false}
 74→            />
 75→            {/* Constellation membership ring */}
 76→            {constellationColor && (
 77→                <Circle
 78→                    radius={r * 2.8}
 79→                    stroke={constellationColor}
 80→                    strokeWidth={1.2}
 81→                    opacity={0.35}
 82→                    dash={[4, 3]}
 83→                    perfectDrawEnabled={false}
 84→                    listening={false}
 85→                />
 86→            )}
 87→            {/* Inner glow — radial gradient */}
 88→            <Circle
 89→                radius={r * 2.2}
 90→                fillRadialGradientStartPoint={{ x: 0, y: 0 }}
 91→                fillRadialGradientEndPoint={{ x: 0, y: 0 }}
 92→                fillRadialGradientStartRadius={0}
 93→                fillRadialGradientEndRadius={r * 2.2}
 94→                fillRadialGradientColorStops={[
 95→                    0, color,
 96→                    0.4, hexToRgba(color, 0.65),
 97→                    1, hexToRgba(color, 0),
 98→                ]}
 99→                perfectDrawEnabled={false}
100→                listening={false}
101→            />
102→            {/* Bright core */}
103→            <Circle
104→                radius={r * 0.5}
105→                fill="#ffffffee"
106→                shadowColor="#ffffff"
107→                shadowBlur={4}
108→                shadowOpacity={1}
109→                perfectDrawEnabled={false}
110→                hitStrokeWidth={r + 12}
111→                onClick={onClick}
112→                onTap={onClick}
113→                onMouseDown={onPointerDown ? (e) => {
114→                    e.cancelBubble = true;
115→                    const screenX = e.evt.clientX;
116→                    const screenY = e.evt.clientY;
117→                    onPointerDown(screenX, screenY);
118→                } : undefined}
119→                onTouchStart={onPointerDown ? (e) => {
120→                    e.cancelBubble = true;
121→                    const touch = e.evt.touches?.[0];
122→                    if (touch) onPointerDown(touch.clientX, touch.clientY);
123→                } : undefined}
124→            />
125→            {showTitle && title && (
126→                <Text
127→                    text={title.length > 24 ? title.slice(0, 22) + '...' : title}
128→                    y={r * 2.2 + 4}
129→                    fontSize={10}
130→                    fill="rgba(255,255,255,0.6)"
131→                    align="center"
132→                    width={120}
133→                    offsetX={60}
134→                    listening={false}
135→                    perfectDrawEnabled={false}
136→                />
137→            )}
138→        </Group>
139→    );
140→});
141→
142→StarGroup.displayName = 'StarGroup';
143→
144→export default StarGroup;
